1	const CURSED_SURCHARGE_RATE = 0.1;
2	const HIGH_ENCHANTMENT_THRESHOLD = 5;
3	const HIGH_ENCHANTMENT_SURCHARGE = 20;
4	const LOYALTY_DISCOUNT_RATE = 0.1;
5	const LOYALTY_THRESHOLD = 2;
6	
7	interface PolicyItem {
8	  baseCost: number;
9	  cursed?: boolean;
10	  enchantment?: number;
11	}
12	
13	interface LoyaltyInfo {
14	  years?: number;
15	}
16	
17	function calculateItemCost(item: PolicyItem): number {
18	  let effectiveCost = item.baseCost + (item.cursed ? item.baseCost * CURSED_SURCHARGE_RATE : 0);
19	  if (item.enchantment && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
20	    effectiveCost += HIGH_ENCHANTMENT_SURCHARGE;
21	  }
22	  return effectiveCost;
23	}
24	
25	function hasEligibleLoyalty(loyalty?: unknown): boolean {
26	  const loyaltyInfo = loyalty as LoyaltyInfo;
27	  return loyaltyInfo?.years !== undefined && loyaltyInfo.years >= LOYALTY_THRESHOLD;
28	}
29	
30	export function quotePolicy(items: unknown, loyalty?: unknown): number {
31	  const policyItems = items as PolicyItem[];
32	  const total = policyItems.reduce((sum, item) => sum + calculateItemCost(item), 0);
33	
34	  if (hasEligibleLoyalty(loyalty)) {
35	    return total - (total * LOYALTY_DISCOUNT_RATE);
36	  }
37	
38	  return total;
39	}
40	
41	export function processClaim(policy: unknown, claims: unknown): number {
42	  throw new Error("Not implemented");
43	}
